#include "TransposedIIRFilter.h"

TransposedIIRFilter::TransposedIIRFilter(float b0, float b1, float a1):
b0(b0),
b1(b1),
a1(a1)
{
	reset();
}

double TransposedIIRFilter::update(double input) {
	output      = b0*input + feedForward - feedBack;
	/*
	Serial.print(" input= ");
	Serial.print(input);
	Serial.print(" ft= ");
	Serial.print(feedForward);
	Serial.print(" fb= ");
	Serial.print(feedBack);
	Serial.print(" o= ");
	Serial.print(output);
	*/
	feedForward = b1*input;
	feedBack    = a1*output;
	return output;
}

void TransposedIIRFilter::reset(){
	feedForward=0;
	feedBack=0;
	error=0;
	output=0;
}

double TransposedIIRFilter::get(){
	return output;
}

TransposedIIRFilter::~TransposedIIRFilter() {

}

/*
 * TransposedIIRFilter.cpp
 *
 * First-order transposed direct-form II IIR filter.
 * All arithmetic in double to preserve coefficient precision and avoid
 * int32_t encoder input truncation above 2^24.
 */

#include "TransposedIIRFilter.h"

TransposedIIRFilter::TransposedIIRFilter(const double b0, const double b1, const double a1)
    : m_b0(b0)
    , m_b1(b1)
    , m_a1(a1)
    , m_feedForward(0.0)
    , m_feedBack(0.0)
    , m_output(0.0)
{
}

double TransposedIIRFilter::update(const double input) {
    m_output      = m_b0 * input + m_feedForward - m_feedBack;
    m_feedForward = m_b1 * input;
    m_feedBack    = m_a1 * m_output;  // note: a1 is stored negative, subtracted above
    return m_output;
}

void TransposedIIRFilter::reset() {
    m_feedForward = 0.0;
    m_feedBack    = 0.0;
    m_output      = 0.0;
}

double TransposedIIRFilter::get() const {
    return m_output;
}

TransposedIIRFilter::~TransposedIIRFilter() = default;

/*
 * PiController.h
 *
 *  Created on: Dec 30, 2022
 *      Author: robot1
 */

#ifndef SRC_TRANSPOSEDIIRFILTER_H_
#define SRC_TRANSPOSEDIIRFILTER_H_

#define VEHICLE_TRANPOSED_IIR_FILTER_SENSOR_B0  0.0591907
#define VEHICLE_TRANPOSED_IIR_FILTER_SENSOR_B1  0.0591907
#define VEHICLE_TRANPOSED_IIR_FILTER_SENSOR_A1  -0.88161859

class TransposedIIRFilter {
public:
	TransposedIIRFilter(float b0,float b1,float a1);
	double update(double input);
	void reset();
	double get();
	virtual ~TransposedIIRFilter();
private:
	float b0;
	float b1;
	float a1;
	double feedForward;
	double feedBack;
	double error;
	double output;
};

#endif /* SRC_TRANSPOSEDIIRFILTER_H_ */

/*
 * TransposedIIRFilter.h
 *
 * First-order transposed direct-form II IIR filter.
 * y[n] = b0*x[n] + b1*x[n-1] + a1*y[n-1]
 *
 * State variables and I/O use double so that:
 *   - velocity-error inputs (double arithmetic) pass through without narrowing.
 *   - int32_t encoder timer deltas (up to 2^31) are represented exactly
 *     (float mantissa is only 24-bit; double covers the full int32_t range).
 *   - the feedback coefficient a1 ≈ -0.88161859 (8 sig figs) is stored
 *     without the ~1 ULP rounding that float storage would introduce.
 */

#ifndef SRC_TRANSPOSEDIIRFILTER_H_
#define SRC_TRANSPOSEDIIRFILTER_H_

// Sensor low-pass IIR coefficients (computed offline, 8 significant digits).
// Stored as double literals — no 'f' suffix — to avoid narrowing to float.
#define VEHICLE_TRANPOSED_IIR_FILTER_SENSOR_B0   0.0591907
#define VEHICLE_TRANPOSED_IIR_FILTER_SENSOR_B1   0.0591907
#define VEHICLE_TRANPOSED_IIR_FILTER_SENSOR_A1  -0.88161859

class TransposedIIRFilter {
public:
    TransposedIIRFilter(double b0, double b1, double a1);

    /**
     * Advance the filter by one sample.
     * @param input  New sample — accepts double velocity error or int32_t
     *               encoder delta (implicitly promoted to double, exact for
     *               all 32-bit integer values).
     * @return       Filtered output.
     */
    double update(double input);

    void   reset();
    double get() const;

    ~TransposedIIRFilter();

private:
    // Coefficients stored as double to preserve all 8 significant digits of a1.
    double m_b0;
    double m_b1;
    double m_a1;

    double m_feedForward;
    double m_feedBack;
    double m_output;
};

#endif /* SRC_TRANSPOSEDIIRFILTER_H_ */
